using UnityEngine;

public class ProjectShipIt : MonoBehaviour
{
    [Header("Game Info")]
    public string gameName = "My First Game";
    public string version = "1.0.0";
    public string releaseDate = "";

    [Header("Credits")]
    public string[] developers;
    public string[] artists;
    public string[] musicians;

    void Start()
    {
        releaseDate = System.DateTime.Now.ToString("yyyy-MM-dd");

        Debug.Log("=== 🎉 SHIP IT! 🎉 ===");
        Debug.Log("Game: " + gameName);
        Debug.Log("Version: " + version);
        Debug.Log("Release Date: " + releaseDate);

        Debug.Log("\n--- Ship Checklist ---");
        Debug.Log("✅ Full playthrough works");
        Debug.Log("✅ All levels playable");
        Debug.Log("✅ No major bugs");
        Debug.Log("✅ Polish pass complete");
        Debug.Log("✅ Build tested on target platform");
        Debug.Log("✅ Published to Itch.io");

        Debug.Log("\n--- You Did It! ---");
        Debug.Log("🎮 You made a game!");
        Debug.Log("📚 You learned: C#, Unity, game design");
        Debug.Log("🚀 You shipped!");

        Debug.Log("\n--- What's Next? ---");
        Debug.Log("1. Make another game");
        Debug.Log("2. Share your game with the world");
        Debug.Log("3. Keep learning!");

        Debug.Log("\n💙 Sharp-chan is proud of you!");
    }

    // Cheat to complete the game
    void Update()
    {
        if (Input.GetKeyDown(KeyCode.End))
        {
            Debug.Log("🏆 Game completed! You win!");
        }
    }
}
